var direction = GetChoice(parameters, "direction", "linearHorizontal");
        // Normalize incoming choice string to avoid hidden whitespace/unicode differences
        direction = (direction ?? string.Empty).Trim();
        var startColor = GetColor(parameters, "startColor", Color.FromRgb(0, 0, 0));
        var r0 = startColor.R / 255f;
        var g0 = startColor.G / 255f;
        var b0 = startColor.B / 255f;
        var endColor = GetColor(parameters, "endColor", Color.FromRgb(255, 255, 255));
        var r1 = endColor.R / 255f;
        var g1 = endColor.G / 255f;
        var b1 = endColor.B / 255f;
        var repeat = Math.Max(1, GetInt(parameters, "repeatCount", 1));
        var offset = GetFloat(parameters, "offset", 0f);
        var midpoint = GetFloat(parameters, "midpoint", 0.5f);
        var rotation = GetFloat(parameters, "rotationAngle", 0f) * MathF.PI / 180f;
        var centerX = GetFloat(parameters, "centerX", 0.5f);
        var centerY = GetFloat(parameters, "centerY", 0.5f);
        var angleOffset = GetFloat(parameters, "angleOffset", 0f) * MathF.PI / 180f;
        var tiling = GetBool(parameters, "tiling", true);
        var invert = GetBool(parameters, "invert");

        var size = context.TileSize;
        var buffer = new PixelBuffer(size, size);

        // GPU accelerated path removed for gradient generation to ensure CPU/GPU
        // output parity. GPU path produced color-channel ordering/packing
        // differences causing incorrect preview colors (e.g. strong yellow tint).
        // Always use the CPU implementation here to guarantee consistent results.
        var cosR = MathF.Cos(rotation);
        var sinR = MathF.Sin(rotation);

        buffer.ParallelForEachPixel((x, y) =>
        {
            var nx = x / (float)(size - 1);
            var ny = y / (float)(size - 1);

            // Apply rotation around center for linear modes
            if (MathF.Abs(rotation) > 0.001f && direction is "linearHorizontal" or "linearVertical" or "diagonal")
            {
                var cx = nx - 0.5f;
                var cy = ny - 0.5f;
                nx = cx * cosR - cy * sinR + 0.5f;
                ny = cx * sinR + cy * cosR + 0.5f;
            }


            float t;
            switch (direction)
            {
                case "linearHorizontal":
                    t = nx;
                    break;
                case "linearVertical":
                    t = ny;
                    break;
                case "diagonal":
                    t = (nx + ny) * 0.5f;
                    break;
                case "radial":
                    var rcx = (nx - centerX) * 2f;
                    var rcy = (ny - centerY) * 2f;
                    t = MathF.Sqrt(rcx * rcx + rcy * rcy);
                    t = Math.Clamp(t, 0f, 1f);
                    break;
                case "angular":
                    var ax = nx - centerX;
                    var ay = ny - centerY;
                    // Apply an angle offset so designers can rotate the angle gradient easily
                    t = (MathF.Atan2(ay, ax) + angleOffset) / MathF.Tau;
                    t = (t + 1f) % 1f;
                    break;
                case "diamond":
                    t = (MathF.Abs(nx - centerX) + MathF.Abs(ny - centerY)) * 2f;
                    t = Math.Clamp(t, 0f, 1f);
                    break;
                default: // linearHorizontal
                    t = nx;
                    break;
            }

            // Apply offset
            t = (t + offset) % 1f;
            if (t < 0f) t += 1f;

            // Apply repeat
            t = (t * repeat) % 1f;

            if (tiling)
            {
                // Triangle wave for seamless tiling: 0→1→0
                t = 1f - MathF.Abs(t * 2f - 1f);
            }

            // Apply midpoint bias
            if (MathF.Abs(midpoint - 0.5f) > 0.001f)
            {
                var bias = MathF.Log(0.5f) / MathF.Log(Math.Clamp(midpoint, 0.01f, 0.99f));
                t = MathF.Pow(t, bias);
            }

            if (invert) t = 1f - t;

            var r = Lerp(r0, r1, t);
            var g = Lerp(g0, g1, t);
            var b = Lerp(b0, b1, t);
            buffer.SetPixel(x, y, r, g, b, 1f);
        });

        return buffer;
}
